from organisms import Organism, ILiving, classify

class Animal(Organism):
    def __init__(self, name: str):
        super().__init__(name)

    @override
    def get_type(self) -> str:
        return "Animal"

class Plant(Organism):
    def __init__(self, name: str):
        super().__init__(name)

    @override
    def get_type(self) -> str:
        return "Plant"

